# Infrastructure-as-code: cost circuit breaker alert
# terraform/modules/agent_monitoring/main.tf
resource "grafana_alert_rule" "cost_circuit_breaker" {
  name      = "${var.capability_name}_cost_circuit_breaker"
  folder_uid = grafana_folder.agent_alerts.uid

  data {
    ref_id = "A"
    query {
      model {
        expr           = "rate(agent_cost_usd_total{capability='${var.capability_name}'}[5m]) * 60"
        datasource_uid = var.prometheus_datasource_uid
      }
    }
  }

  condition   = "B"
  no_data_state = "NoData"

  annotations = {
    summary     = "${var.capability_name} cost circuit breaker triggered"
    description = "Per-request cost exceeds 2x baseline. Check for unexpected token usage."
    runbook_url = "https://docs.internal.example.com/runbooks/${var.capability_name}"
  }

  labels = {
    severity   = "warning"
    capability = var.capability_name
    team       = var.team_name
  }
}
